export function getItemById(itemId: number): ItemReference | undefined {
  return ITEMS.find((item) => item.id === itemId)
}

export function parseItemSet(value: string | null | undefined): ItemReference[] {
  if (!value) return []
  return value.split('>').map((segment) => Number(segment.trim())).filter((itemId) => Number.isInteger(itemId) && itemId > 0).map((itemId) => getItemById(itemId) ?? { id: itemId, name: `Item ${itemId}`, image: '' })
}